VALUES
  ('public-health-specialist-moex-00877', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於世代研究法（cohortstudy），下列何者正確？', '["以世代研究法研究長誘導期（inductionperiod）的罕見疾病（raredisease），需要長期追蹤大 量的研究對象，研究成本過高，可行性低", "為了降低世代研究法研究長期追蹤大量研究對象的成本，不宜運用現有的疾病通報或登記 系統以監測疾病的發生", "回溯性世代研究法（retrospectivecohortstudy）較前瞻性世代研究法（prospectivecohortstudy） 成本高", "運用既有的全人口（generalpopulation）的資料取代非暴露組（unexposedgroup）或對照組 （referencegroup），無法降低世代研究法研究長期追蹤大量研究對象的成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00878', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '病例對照研究法的缺點有那些？①需要較大樣本  ②無法計算發生率  ③長期追蹤費時較長', '["容易有選樣偏差", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00879', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某學校發生疑似食因性傳染病事件，初步調查發現，出現腸胃道症狀學生的發病時間集中在 午餐後4-10小時，研判可能與食用午餐的某道沙拉有關。調查人員比較有出現腸胃道症狀的 學生與未出現腸胃道症狀的學生，兩組所食用菜餚的差異，計算每道菜餚的勝算比（oddsratio, OR）。請問調查員使用的是何種研究法？', '["生態研究（ecologicstudy）", "世代研究法（cohortstudy）", "病例對照研究法（case-controlstudy）", "橫斷研究法（cross-sectionalstudy）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00880', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列何者不是病例對照研究結果有偏誤的原因？', '["資料分析時忘記控制干擾因子", "病例組與對照組來自不同的標的族群", "病例組與對照組回憶危險因子暴露的準確度有異", "病人加入病例組與健康人加入對照組的比例不同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00881', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於流行病學的測量，下列何者正確？', '["不同縣市國中生之吸菸率因為是來自個別國中生的吸菸率調查，故屬於個體層次的變項 （individual-levelvariables）", "行政院環境保護署空氣品質監測網的全國各地區 PM 2.5 濃度無法反映該地區個人暴露的 差異，故並不屬於群體層次的變項（macro-levelvariables）", "各縣市的人口密度以及醫療資源，屬於群體層次的變項（macro-levelvariables）", "群體層次的變項（macro-level variables）無法用之於個體層次之分析（individual-level analysis）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00882', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關年齡效應（ageeffect）、年代效應（periodeffect）與世代效應（cohorteffect），下列敘述 何者正確？', '["臺灣自1986年起擴大對所有新生兒全面免費注射B型肝炎疫苗，目前35歲以下族群的B 型肝炎感染大幅減少，此為預防接種政策的年代效應（periodeffect）", "針具注射是造成 C 型肝炎傳染的重要原因。臺灣在 1980 年代推廣使用拋棄式針具，目前", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00883', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '歲以下族群之 C 型肝炎盛行率明顯降低，此為拋棄式針具推廣政策的年齡效應（age effect）', '["飲食行為和飲食習慣的改變導致兒童肥胖盛行率上升，此為世代效應（cohorteffect）", "1997年全民健保為強化結核病個案之發現，實施不通報則不給付的政策，使得結核病通報 個案急速增加，此為世代效應（cohorteffect）", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00884', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某研究為了探討飲用蔓越莓果汁是否預防婦女泌尿道感染，招募一群婦女，隨機分配兩組， 一組第一個月每天飲用固定量蔓越莓汁，第二個月飲用顏色與味道相同的安慰劑飲品；第二 組在第一個月飲用上述安慰劑飲品，第二個月飲用蔓越莓汁。研究者記錄受試者在其間發生 泌尿道感染的次數。這樣的研究設計稱為：', '["平行試驗", "交叉試驗", "多因子試驗", "病例交叉研究"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00885', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關於描述性流行病學分析（descriptiveepidemiology），下列何者正確？', '["描述性流行病學分析疾病發生的人、時、地特徵，常能直接指出疾病發生的原因", "不論欲探討的疾病為何，最好以「月」為固定使用的時間間隔，分析疾病發生的時間趨勢， 較能有一致性的比較基準", "公共衛生監測（publichealthsurveillance）常使用臨床醫療的通報資料進行分析，此時，不 必考慮城鄉醫療資源落差造成的通報差異", "描述性流行病學分析疾病發生的人的特性時，年齡和性別是最常見最基本的變項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00886', 'public-health-specialist', 'public-health-specialist-moex-110-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '探討暴露與疾病之因果關係的研究可能存在干擾因子，下列對干擾因子的敘述，何者錯誤？', '["干擾因子與暴露有相關，但不得為暴露的結果", "干擾因子與疾病的發生有相關", "對干擾因子分層後，暴露對疾病的效應將會一致", "干擾作用對推論的影響方向不一定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "af0dd5741a01", "answer_pdf_sha1": "9b67e73067d2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
